const body = $input.item.json.body || $input.item.json;
const productData = {
  product_name: body.product_info?.name || '',
  category: body.product_info?.category || '',
  price: body.product_info?.price || 0,
  sale_price: body.product_info?.sale_price || 0,
  discount_percent: body.product_info?.discount_percent || 0,
  main_benefit: body.product_details?.main_benefit || '',
  problem_solved: body.product_details?.problem_solved || '',
  usp: body.product_details?.usp || body.product_details?.main_benefit || '',
  target_audience: body.target_audience?.primary || '',
  pain_points: body.target_audience?.pain_points || []
};
return { json: productData };

