const items = $input.all();
const productData = $node['Extract Product Data'].json;
const timestamp = new Date().toISOString();
const batchId = `creative_v2_${timestamp.split('T')[0].replace(/-/g, '')}_${Math.random().toString(36).substr(2, 6)}`;

const tiktokScripts = [];
const reelsScripts = [];
let midjourneyPrompts = [];

for (const item of items) {
  if (!item.json.choices) continue;
  const content = item.json.choices[0].message.content;

  try {
    const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleaned);

    if (parsed.creative_id) {
      if (parsed.creative_id.includes('tiktok')) {
        tiktokScripts.push(parsed);
      } else if (parsed.creative_id.includes('reels')) {
        reelsScripts.push(parsed);
      }
    }

    if (parsed.midjourney_prompts) {
      midjourneyPrompts = parsed.midjourney_prompts;
    }
  } catch (e) {
    console.log('Parse error:', e.message);
  }
}

